// بيانات اللاعب
struct Player {
    float health;
    float maxHealth;
};

void DrawPlayerHealthBar(const Player& player) {
    Vector2 position = {20.0f, 20.0f};  // الزاوية العلوية اليسرى
    Vector2 size = {200.0f, 20.0f};     // حجم الشريط

    // حساب النسبة المئوية
    float healthPercent = player.health / player.maxHealth;

    // رسم الخلفية (الشريط الفارغ)
    DrawRectangle(position.x, position.y, size.x, size.y, Color{50, 50, 50, 200});

    // رسم التعبئة (الصحة الحالية)
    Color healthColor = (healthPercent > 0.5f) ? Color{0, 200, 0, 255} :
                        (healthPercent > 0.25f) ? Color{255, 165, 0, 255} :
                                                  Color{200, 0, 0, 255};
    DrawRectangle(position.x, position.y, size.x * healthPercent, size.y, healthColor);

    // رسم الإطار
    DrawRectangleLines(position.x, position.y, size.x, size.y, Color{255, 255, 255, 150});

    // رسم النص (اختياري)
    char healthText[32];
    sprintf(healthText, "%.0f / %.0f", player.health, player.maxHealth);
    DrawText(healthText, position.x + 10, position.y + 2, 14, Color{255, 255, 255, 255});
}

struct Player {
    float health, maxHealth;
    float mana, maxMana;
};

void DrawPlayerBars(const Player& player) {
    Vector2 basePos = {20.0f, 20.0f};

    // شريط الصحة
    DrawHealthBar(player.health, player.maxHealth, basePos, {200.0f, 20.0f}, Color{200, 0, 0});

    // شريط المانا (أسفل الصحة)
    Vector2 manaPos = {basePos.x, basePos.y + 25.0f};
    float manaPercent = player.mana / player.maxMana;

    // خلفية
    DrawRectangle(manaPos.x, manaPos.y, 200.0f, 15.0f, Color{30, 30, 80, 200});
    // تعبئة زرقاء
    DrawRectangle(manaPos.x, manaPos.y, 200.0f * manaPercent, 15.0f, Color{30, 100, 200});
    // إطار
    DrawRectangleLines(manaPos.x, manaPos.y, 200.0f, 15.0f, Color{100, 150, 255, 150});
}

struct StaminaSystem {
    float current;
    float maximum;
    float regenRate;      // معدل الشحن في الثانية
    float drainRate;      // معدل الاستنزاف عند الجري
    bool isRunning;
};

void UpdateStamina(StaminaSystem& stamina, float deltaTime) {
    if (stamina.isRunning && stamina.current > 0) {
        stamina.current -= stamina.drainRate * deltaTime;
        if (stamina.current < 0) stamina.current = 0;
    } else if (!stamina.isRunning && stamina.current < stamina.maximum) {
        stamina.current += stamina.regenRate * deltaTime;
        if (stamina.current > stamina.maximum) stamina.current = stamina.maximum;
    }
}

void DrawStaminaBar(const StaminaSystem& stamina, Vector2 position) {
    float percent = stamina.current / stamina.maximum;

    // خلفية شفافة
    DrawRectangle(position.x, position.y, 180.0f, 12.0f, Color{30, 50, 30, 180});

    // تعبئة خضراء مع تدرج
    Color staminaColor = Color{50, 200, 50, 255};
    DrawRectangleGradientH(position.x, position.y, 180.0f * percent, 12.0f,
                           Color{80, 220, 80}, Color{50, 180, 50});

    // وميض عند الاستنزاف الكامل
    if (stamina.current < 10.0f) {
        float pulse = sinf(GetTime() * 8.0f) * 0.5f + 0.5f;
        DrawRectangle(position.x, position.y, 180.0f, 12.0f,
                      Color{255, 0, 0, (unsigned char)(pulse * 100)});
    }
}

struct PlayerProgress {
    int level;
    float currentXP;
    float xpToNextLevel;
};

void DrawXPBar(const PlayerProgress& progress) {
    // في أسفل الشاشة
    Vector2 position = {GetScreenWidth() / 2.0f - 150.0f, GetScreenHeight() - 40.0f};
    Vector2 size = {300.0f, 16.0f};

    float percent = progress.currentXP / progress.xpToNextLevel;

    // خلفية
    DrawRectangle(position.x, position.y, size.x, size.y, Color{20, 20, 40, 200});

    // تدرج ذهبي
    DrawRectangleGradientH(position.x, position.y, size.x * percent, size.y,
