    // نص المستوى
    char levelText[64];
    sprintf(levelText, "المستوى %d  |  %.0f / %.0f XP",
            progress.level, progress.currentXP, progress.xpToNextLevel);
    DrawText(levelText, position.x + 10, position.y + 1, 12, Color{255, 255, 200});
}

struct Boss {
    const char* name;
    float health;
    float maxHealth;
    int phase;           // المرحلة الحالية
    int totalPhases;     // عدد المراحل الإجمالي
};

void DrawBossHealthBar(const Boss& boss) {
    // في أعلى الشاشة، بالمنتصف
    float barWidth = 500.0f;
    float barHeight = 30.0f;
    Vector2 position = {GetScreenWidth() / 2.0f - barWidth / 2.0f, 50.0f};

    // اسم الزعيم
    DrawText(boss.name, position.x, position.y - 30, 24, Color{255, 50, 50});

    // خلفية داكنة مع إطار مزخرف
    DrawRectangle(position.x - 4, position.y - 4, barWidth + 8, barHeight + 8, Color{80, 0, 0});
    DrawRectangle(position.x, position.y, barWidth, barHeight, Color{30, 0, 0});

    // تقسيم الشريط إلى مراحل
    float phaseWidth = barWidth / boss.totalPhases;
    float healthPercent = boss.health / boss.maxHealth;

    // رسم كل مقطع
    for (int i = 0; i < boss.totalPhases; i++) {
        float segStart = i * phaseWidth;
        float segEnd = (i + 1) * phaseWidth;

        // حساب التعبئة لهذا المقطع
        float fillStart = position.x + segStart;
        float fillWidth = 0;

        float globalStart = i / (float)boss.totalPhases;
        float globalEnd = (i + 1) / (float)boss.totalPhases;

        if (healthPercent > globalStart) {
            float segPercent = (healthPercent - globalStart) / (globalEnd - globalStart);
            segPercent = fminf(segPercent, 1.0f);
            fillWidth = phaseWidth * segPercent;

            // لون مختلف لكل مرحلة
            Color phaseColor;
            switch(i) {
                case 0: phaseColor = Color{200, 50, 50}; break;
                case 1: phaseColor = Color{200, 100, 50}; break;
                case 2: phaseColor = Color{150, 50, 150}; break;
                default: phaseColor = Color{200, 50, 50}; break;
            }

            DrawRectangle(fillStart, position.y, fillWidth, barHeight, phaseColor);
        }

        // خط فاصل بين المقاطع
        if (i > 0) {
            DrawLine(position.x + segStart, position.y,
                     position.x + segStart, position.y + barHeight,
                     Color{100, 100, 100});
        }
    }

    // إطار خارجي
    DrawRectangleLines(position.x - 2, position.y - 2, barWidth + 4, barHeight + 4, Color{255, 200, 0});
}

struct MinimapConfig {
    Vector2 position;        // مركز الخريطة على الشاشة
    float radius;            // نصف قطر الخريطة الدائرية
    float worldRadius;       // نصف قطر المنطقة المعروضة من العالم
    Texture2D mapTexture;    // نسيج الخريطة
};

struct MapMarker {
    Vector2 worldPos;
    Color color;
    const char* label;
    bool isEnemy;
    bool isObjective;
};

void DrawMinimap(const MinimapConfig& config, const Vector2& playerPos,
                 float playerRotation, const std::vector<MapMarker>& markers) {
    // رسم الخلفية الدائرية
    DrawCircle(config.position.x, config.position.y, config.radius + 2, Color{0, 0, 0, 180});

    // قص الرسم داخل الدائرة
    BeginScissorMode(config.position.x - config.radius, config.position.y - config.radius,
                     config.radius * 2, config.radius * 2);

    // حساب إزاحة الخريطة بناءً على موقع اللاعب
    float scale = config.radius / config.worldRadius;

    // رسم نسيج الخريطة (متحرك مع اللاعب)
    Rectangle srcRec = {
        playerPos.x - config.worldRadius,
        playerPos.y - config.worldRadius,
        config.worldRadius * 2,
        config.worldRadius * 2
    };
    Rectangle destRec = {
        config.position.x - config.radius,
        config.position.y - config.radius,
        config.radius * 2,
        config.radius * 2
    };
    DrawTexturePro(config.mapTexture, srcRec, destRec, {0, 0}, 0.0f, Color{255, 255, 255, 200});

    // رسم العلامات
    for (const auto& marker : markers) {
        Vector2 relativePos = {
            (marker.worldPos.x - playerPos.x) * scale,
            (marker.worldPos.y - playerPos.y) * scale
        };

        // التحقق من أن العلامة داخل نطاق الخريطة
        if (sqrtf(relativePos.x * relativePos.x + relativePos.y * relativePos.y) < config.radius) {
            Vector2 screenPos = {config.position.x + relativePos.x, config.position.y + relativePos.y};

            if (marker.isEnemy) {
                DrawTriangle({screenPos.x, screenPos.y - 6},
                            {screenPos.x - 5, screenPos.y + 4},
                            {screenPos.x + 5, screenPos.y + 4},
                            Color{255, 50, 50});
            } else if (marker.isObjective) {
                DrawCircle(screenPos.x, screenPos.y, 5, Color{255, 200, 0});
            } else {
                DrawCircle(screenPos.x, screenPos.y, 3, marker.color);
            }
        }
    }

    EndScissorMode();

    // إطار دائري
    DrawCircleLines(config.position.x, config.position.y, config.radius, Color{255, 255, 255, 150});

    // سهم اللاعب في المركز
    Vector2 arrowTip = {
        config.position.x + sinf(playerRotation) * 10,
        config.position.y - cosf(playerRotation) * 10
    };
    DrawTriangle(arrowTip,
                {config.position.x - sinf(playerRotation + 0.5f) * 7 - cosf(playerRotation + 0.5f) * 7,
                 config.position.y + cosf(playerRotation + 0.5f) * 7 - sinf(playerRotation + 0.5f) * 7},
                {config.position.x - sinf(playerRotation - 0.5f) * 7 + cosf(playerRotation - 0.5f) * 7,
                 config.position.y + cosf(playerRotation - 0.5f) * 7 + sinf(playerRotation - 0.5f) * 7},
                Color{0, 150, 255});
}

struct Weapon {
    const char* name;
    int currentAmmo;
    int magazineSize;
    int reserveAmmo;
    Texture2D icon;
};

void DrawAmmoCounter(const Weapon& weapon) {
    // في الزاوية السفلية اليمنى
    float screenWidth = GetScreenWidth();
    float screenHeight = GetScreenHeight();
    Vector2 position = {screenWidth - 200.0f, screenHeight - 80.0f};

    // خلفية شبه شفافة
    DrawRectangle(position.x - 10, position.y - 10, 190, 70, Color{0, 0, 0, 150});

    // أيقونة السلاح
    DrawTexture(weapon.icon, position.x, position.y, Color{255, 255, 255, 200});

    // عدد الطلقات الحالية (كبير)
    char ammoText[16];
    sprintf(ammoText, "%d", weapon.currentAmmo);
    DrawText(ammoText, position.x + 70, position.y, 36,
             weapon.currentAmmo <= weapon.magazineSize * 0.25 ? Color{255, 50, 50} : Color{255, 255, 255});

    // الفاصل
    DrawText("/", position.x + 110, position.y + 15, 20, Color{150, 150, 150});

    // الذخيرة الاحتياطية
    char reserveText[16];
    sprintf(reserveText, "%d", weapon.reserveAmmo);
    DrawText(reserveText, position.x + 125, position.y + 15, 20, Color{150, 150, 150});

    // اسم السلاح
    DrawText(weapon.name, position.x + 70, position.y + 40, 14, Color{200, 200, 200});

    // تحذير عند الذخيرة المنخفضة
    if (weapon.currentAmmo <= weapon.magazineSize * 0.25 && weapon.currentAmmo > 0) {
        float pulse = sinf(GetTime() * 6.0f) * 0.5f + 0.5f;
        DrawText("LOW AMMO", position.x + 70, position.y - 25, 12,
                 Color{255, (unsigned char)(100 + pulse * 100), 0, 255});
    } else if (weapon.currentAmmo == 0) {
        DrawText("RELOAD [R]", position.x + 70, position.y - 25, 12, Color{255, 50, 50});
    }
}

struct Ability {
    const char* name;
    Texture2D icon;
    float cooldownTime;     // إجمالي وقت التهدئة
    float currentCooldown;  // الوقت المتبقي
    int keyBinding;         // مفتاح التفعيل
};

void DrawAbilitySlot(const Ability& ability, Vector2 position, float size) {
    // رسم الأيقونة
    Rectangle destRec = {position.x, position.y, size, size};
    DrawTexturePro(ability.icon, {0, 0, (float)ability.icon.width, (float)ability.icon.height},
                   destRec, {0, 0}, 0.0f, Color{255, 255, 255, 255});

    // إذا كانت القدرة في فترة تهدئة
    if (ability.currentCooldown > 0) {
        // تعتيم الأيقونة
        DrawRectangle(position.x, position.y, size, size, Color{0, 0, 0, 150});

        // رسم القوس الدائري للتهدئة
        float cooldownPercent = ability.currentCooldown / ability.cooldownTime;
        float startAngle = -90.0f;  // البدء من الأعلى
        float endAngle = startAngle + (360.0f * cooldownPercent);

        DrawRing({position.x + size/2, position.y + size/2}, size/2 - 4, size/2,
                 startAngle * DEG2RAD, endAngle * DEG2RAD, 0, Color{255, 255, 255, 200});

        // عرض الثواني المتبقية
        char cooldownText[8];
        sprintf(cooldownText, "%.1f", ability.currentCooldown);
        int textWidth = MeasureText(cooldownText, 16);
        DrawText(cooldownText, position.x + (size - textWidth)/2, position.y + size/2 - 8,
                 16, Color{255, 255, 255});
    } else {
        // القدرة جاهزة - إطار مضيء
        DrawRectangleLines(position.x, position.y, size, size, Color{100, 200, 100, 200});
    }

    // مفتاح التفعيل
    char keyText[4];
    sprintf(keyText, "%c", (char)ability.keyBinding);
    DrawText(keyText, position.x + 4, position.y + size - 16, 12, Color{255, 255, 0});
}

struct CrosshairConfig {
    float baseSize;         // الحجم الأساسي
    float spreadMultiplier; // معامل الانتشار
    Color color;
    float thickness;
    float gap;
};

void DrawCrosshair(const CrosshairConfig& config, bool isMoving, bool isAiming, bool isShooting) {
    Vector2 center = {GetScreenWidth() / 2.0f, GetScreenHeight() / 2.0f};

    // حساب الحجم بناءً على الحالة
    float size = config.baseSize;
    float gap = config.gap;

    if (isMoving) {
        size *= 1.5f;
        gap *= 1.5f;
    }
    if (isAiming) {
        size *= 0.6f;
        gap *= 0.6f;
    }
    if (isShooting) {
        size *= 2.0f;
        gap *= 2.0f;
    }

    // رسم أربعة خطوط
    // الأعلى
    DrawLine(center.x, center.y - gap, center.x, center.y - gap - size, config.color);
    // الأسفل
    DrawLine(center.x, center.y + gap, center.x, center.y + gap + size, config.color);
    // اليسار
    DrawLine(center.x - gap, center.y, center.x - gap - size, center.y, config.color);
    // اليمين
    DrawLine(center.x + gap, center.y, center.x + gap + size, center.y, config.color);

    // نقطة في المركز (اختياري)
    DrawCircle(center.x, center.y, 2, config.color);

    // إذا كان يصوب - إضافة دقة
    if (isAiming) {
        DrawCircleLines(center.x, center.y, size + 5, Color{255, 255, 255, 100});
    }
}

struct FloatingText {
    char text[16];
    Vector2 position;
    Vector2 velocity;
    Color color;
    float lifetime;
    float maxLifetime;
    float scale;
};

std::vector<FloatingText> floatingTexts;

void SpawnDamageText(Vector2 worldPos, int damage, bool isCritical, bool isHeal) {
    FloatingText ft;
    ft.position = worldPos;
    ft.velocity = { (float)(rand() % 60 - 30), -80.0f };  // حركة عشوائية للأعلى

    if (isHeal) {
        sprintf(ft.text, "+%d", damage);
        ft.color = Color{50, 255, 50};
        ft.scale = 1.0f;
    } else if (isCritical) {
        sprintf(ft.text, "%d!", damage);
        ft.color = Color{255, 200, 0};
        ft.scale = 1.5f;
    } else {
        sprintf(ft.text, "%d", damage);
        ft.color = Color{255, 255, 255};
        ft.scale = 1.0f;
    }

    ft.lifetime = 1.5f;
    ft.maxLifetime = 1.5f;

    floatingTexts.push_back(ft);
}

void UpdateFloatingTexts(float deltaTime) {
    for (auto& ft : floatingTexts) {
        ft.position.x += ft.velocity.x * deltaTime;
        ft.position.y += ft.velocity.y * deltaTime;
        ft.velocity.y += 50.0f * deltaTime;  // جاذبية خفيفة
        ft.lifetime -= deltaTime;
    }

    // إزالة النصوص المنتهية
    floatingTexts.erase(
        std::remove_if(floatingTexts.begin(), floatingTexts.end(),
                       [](const FloatingText& ft) { return ft.lifetime <= 0; }),
        floatingTexts.end()
    );
}

void DrawFloatingTexts() {
    for (const auto& ft : floatingTexts) {
        float alpha = ft.lifetime / ft.maxLifetime;
        Color fadeColor = { ft.color.r, ft.color.g, ft.color.b, (unsigned char)(alpha * 255) };

        int fontSize = (int)(20 * ft.scale);
        DrawText(ft.text, (int)ft.position.x, (int)ft.position.y, fontSize, fadeColor);
    }
}

struct QuestObjective {
    const char* description;
    int current;
    int required;
    bool isCompleted;
};

struct Quest {
    const char* title;
    std::vector<QuestObjective> objectives;
    bool isTracked;  // هل يتم تتبعها حالياً
};

void DrawQuestTracker(const std::vector<Quest>& quests) {
    Vector2 position = {GetScreenWidth() - 260.0f, 100.0f};
    float maxWidth = 250.0f;

    // عنوان
    DrawText("المهام النشطة", position.x, position.y, 16, Color{255, 200, 100});
    position.y += 25;

    for (const auto& quest : quests) {
        if (!quest.isTracked) continue;

        // خلفية المهمة
        float questHeight = 30 + quest.objectives.size() * 22;
        DrawRectangle(position.x - 5, position.y - 5, maxWidth, questHeight, Color{0, 0, 0, 150});

        // اسم المهمة
        DrawText(quest.title, position.x, position.y, 14, Color{255, 220, 100});
        position.y += 20;

        // الأهداف
        for (const auto& obj : quest.objectives) {
            Color objColor = obj.isCompleted ? Color{100, 200, 100} : Color{200, 200, 200};

            char objectiveText[128];
            sprintf(objectiveText, "• %s: %d/%d", obj.description, obj.current, obj.required);
            DrawText(objectiveText, position.x + 10, position.y, 12, objColor);

            // علامة إتمام
            if (obj.isCompleted) {
                DrawText("✓", position.x + maxWidth - 20, position.y, 12, Color{100, 200, 100});
            }

            position.y += 20;
        }

        position.y += 10;  // مسافة بين المهام
    }
}

struct GameTimer {
    float timeRemaining;
    float totalTime;
    bool isRunning;
    bool isCountdown;  // true = تنازلي، false = تصاعدي
};

void DrawGameTimer(const GameTimer& timer) {
    Vector2 position = {GetScreenWidth() / 2.0f - 60, 20.0f};

    int totalSeconds;
    int minutes, seconds, milliseconds;

    if (timer.isCountdown) {
        totalSeconds = (int)timer.timeRemaining;
        minutes = totalSeconds / 60;
        seconds = totalSeconds % 60;
        milliseconds = (int)((timer.timeRemaining - totalSeconds) * 100);
    } else {
        float elapsed = timer.totalTime - timer.timeRemaining;
        totalSeconds = (int)elapsed;
        minutes = totalSeconds / 60;
        seconds = totalSeconds % 60;
        milliseconds = (int)((elapsed - totalSeconds) * 100);
    }

    // تحديد اللون بناءً على الوقت المتبقي
    Color timerColor = Color{255, 255, 255};
    if (timer.isCountdown && timer.timeRemaining < 30.0f) {
        timerColor = Color{255, 200, 0};  // برتقالي
    }
    if (timer.isCountdown && timer.timeRemaining < 10.0f) {
        float pulse = sinf(GetTime() * 8.0f) * 0.5f + 0.5f;
        timerColor = Color{255, (unsigned char)(50 + pulse * 100), 50};  // أحمر نابض
    }

    // خلفية
    DrawRectangle(position.x - 10, position.y - 5, 140, 40, Color{0, 0, 0, 150});

    // الوقت
    char timeText[16];
    sprintf(timeText, "%02d:%02d.%02d", minutes, seconds, milliseconds);
    DrawText(timeText, position.x, position.y, 28, timerColor);

    // أيقونة
    const char* icon = timer.isCountdown ? "⏱️" : "⏱️";
    DrawText(icon, position.x - 30, position.y + 2, 24, Color{255, 255, 255});
}
